    for (const itemSomeBytes of that.someBytes) {
      parts.push(openTag("v"));
      parts.push(serializeBase64EncodedBytesText(itemSomeBytes));
      parts.push(closeTag("v"));
    }
    parts.push(closeTag("someBytes"));

